sp_widget.client_script:
api.controller=function($location) {
  /* widget controller */
  var c = this;

	c.goBack = function() {
        window.history.back();
    };

	c.goTo = function(view) {

        c.view = view;


			 if (view === 'viewDataModel') {
            var url = '/incentiq?id=view_data_model_internal';
            $location.url(url);
            return;
        }
		else if (view === 'createModel') {
            var url = '/incentiq?id=create_data_model_internal';
            $location.url(url);
            return;
        }

		//view_data_model
	}
};

sp_widget.css:
.admin-main h1 {
  font-weight: 600;
  color: #111827;
}

.admin-card-row {
  display: flex;
  gap: 20px;
  align-items: stretch;
}

.admin-card-col {
  display: flex;
  flex: 1;
}

.admin-card {
  width: 100%;
  padding: 22px;
  border-radius: 18px;
  border: 1px solid #e6e8ec;
  background: linear-gradient(180deg, #ffffff, #f9fafb);
  transition: all 0.3s ease;
  cursor: pointer;
  display: flex;
  flex-direction: column;
}

.admin-card i {
  font-size: 22px;
  margin-bottom: 10px;
}

.admin-card h4 {
  font-weight: 600;
  margin-top: 6px;
}

.admin-card:hover {
  transform: translateY(-6px) scale(1.01);
  box-shadow: 0 14px 40px rgba(0,0,0,0.12);
}


.admin-back-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  background: #ffffff;
  border: 1.5px solid #e2e8f0;
  cursor: pointer;
  color: #374151;
  flex-shrink: 0;
  transition: background 0.15s, border-color 0.15s;
}

.admin-back-btn:hover {
  background: #f1f5f9;
  border-color: #94a3b8;
}

.admin-page-topbar-title {
  font-size: 22px;
  font-weight: 800;
  color: #0f172a;
  flex: 1;
}



.admin-page-header p {
  margin: 4px 0 0;
  color: #6b7280;
}

.admin-page-topbar {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #e2e8f0;
}


.card-container {
  background: #ffffff;
  padding: 16px 20px;
  border-radius: 16px;
  border: 1px solid #e6e8ec;
  box-shadow: 0 6px 18px rgba(0,0,0,0.05);
}

.admin-card-row {
  display: flex;
  gap: 20px;
}

.admin-card-col {
  flex: 1;
  display: flex;
}




@media (max-width: 768px) {
  .admin-card-row {
    flex-direction: column;
  }
}
